// Gera o load_id deste run de embeddings para rastreabilidade em pipeline_runs / ingestion_log.
const now = new Date();
const pad = (n) => String(n).padStart(2, '0');
const stamp = `${now.getUTCFullYear()}${pad(now.getUTCMonth() + 1)}${pad(now.getUTCDate())}${pad(now.getUTCHours())}${pad(now.getUTCMinutes())}${pad(now.getUTCSeconds())}`;
return [{
  json: {
    load_id: `EMBED_${stamp}`,
    workflow: '02_pipeline_embeddings',
    started_at: now.toISOString(),
    embed_model: $env.EMBED_MODEL || 'text-embedding-3-small',
  },
}];

// Transforma cada linha empresa-mês em uma narrativa em PT-BR (PME = 'fact narrative').
// Esses textos são os chunks de cockpit.kb_documents que serão embeddados.
const fmtBRL = (v) => {
  const n = Number(v) || 0;
  return n.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL', maximumFractionDigits: 0 });
};
const fmtPct = (v) => `${(Number(v) || 0).toLocaleString('pt-BR', { minimumFractionDigits: 1, maximumFractionDigits: 1 })}%`;

const out = [];
for (const item of $input.all()) {
  const r = item.json;
  const titulo = `Desempenho da ${r.company_name} em ${r.periodo}`;
  const content =
    `Em ${r.periodo}, a empresa ${r.company_name} (${r.company_id}) apresentou ` +
    `receita líquida de ${fmtBRL(r.receita_liquida)}, ` +
    `lucro bruto de ${fmtBRL(r.lucro_bruto)} (margem bruta ${fmtPct(r.margem_bruta_pct)}), ` +
    `EBITDA de ${fmtBRL(r.ebitda)} (margem EBITDA ${fmtPct(r.margem_ebitda_pct)}), ` +
    `EBIT de ${fmtBRL(r.ebit)} e ` +
    `lucro líquido de ${fmtBRL(r.lucro_liquido)} (margem líquida ${fmtPct(r.margem_liquida_pct)}). ` +
    `A dívida líquida foi de ${fmtBRL(r.divida_liquida)}, ` +
    `o capital de giro de ${fmtBRL(r.capital_giro)} e ` +
    `o prazo médio de recebimento (DSO) de ${(Number(r.dso_dias) || 0).toLocaleString('pt-BR', { maximumFractionDigits: 1 })} dias.`;

  const metadata = {
    company_id: r.company_id,
    company_name: r.company_name,
    periodo: r.periodo,
    receita_liquida: r.receita_liquida,
    ebitda: r.ebitda,
    lucro_liquido: r.lucro_liquido,
    margem_ebitda_pct: r.margem_ebitda_pct,
    divida_liquida: r.divida_liquida,
    dso_dias: r.dso_dias,
  };

  out.push({
    json: {
      doc_type: 'fact_narrative',
      company_id: r.company_id,
      period_date: r.period_date,
      title: titulo,
      content,
      metadata,
      embed_model: $('Abrir Run de Embeddings').first().json.embed_model,
      load_id: $('Abrir Run de Embeddings').first().json.load_id,
    },
  });
}
return out;

// Prepara o item para a chamada de embeddings: precisamos do doc_id (do RETURNING) e do texto.
return {
  json: {
    doc_id: $json.id,
    content: $json.content,
    embed_model: $env.EMBED_MODEL || 'text-embedding-3-small',
    load_id: $('Abrir Run de Embeddings').first().json.load_id,
  },
};

// Extrai o vetor da resposta do endpoint de embeddings (formato OpenAI-compatível:
// { data: [ { embedding: [...] } ], model: '...' }). Formata como literal de vetor pgvector.
const resp = $json;
let vector = null;
let model = $('Anexar doc_id ao Conteúdo').item.json.embed_model;

if (resp && Array.isArray(resp.data) && resp.data[0] && Array.isArray(resp.data[0].embedding)) {
  vector = resp.data[0].embedding;
  if (resp.model) model = resp.model;
} else if (Array.isArray(resp.embedding)) {
  vector = resp.embedding;
} else if (Array.isArray(resp)) {
  vector = resp;
}

if (!vector || vector.length === 0) {
  throw new Error('Resposta de embeddings sem vetor válido: ' + JSON.stringify(resp).slice(0, 300));
}

// Literal de vetor pgvector: '[0.1,0.2,...]'
const vectorLiteral = '[' + vector.map((x) => Number(x)).join(',') + ']';

return {
  json: {
    doc_id: $('Anexar doc_id ao Conteúdo').item.json.doc_id,
    model,
    dim: vector.length,
    embedding: vectorLiteral,
    load_id: $('Anexar doc_id ao Conteúdo').item.json.load_id,
  },
};
